import numpy as np

def safe_cosine(x, y, eps=1e-12):
    nx, ny = np.linalg.norm(x), np.linalg.norm(y)
    if nx < eps or ny < eps:
        return 0.0                 # undefined: treat as no similarity
    return float(x @ y) / (nx * ny)

print(safe_cosine(np.zeros(3), np.array([1., 2., 3.])))   # 0.0, no NaN
